<?php
$filename = 'yourfile.php'; // Change this to your file name
$lines = file($filename);

$filtered_lines = array_filter($lines, function($line) {
    return !preg_match('/^\/\*\*.*\*\/$/', $line) && !preg_match('/^Copyright.*$/', $line);
});

file_put_contents($filename, implode('', $filtered_lines));
?>
